class Solution:
    def beautifulSplits(self, nums):
        n = len(nums)
        count = 0
        for i in range(1, n - 1):
            for j in range(i + 1, n):
                nums1 = nums[0:i]
                nums2 = nums[i:j]
                nums3 = nums[j:n]
                condA = len(nums1) <= len(nums2) and nums2[:len(nums1)] == nums1
                condB = len(nums2) <= len(nums3) and nums3[:len(nums2)] == nums2
                if condA or condB:
                    count += 1
        return count

