class Solution:
    def beautifulSplits(self, nums):
        n = len(nums)
        count = 0
        for i in range(1, n - 1):
            condA_ok = False
            if 2 * i <= n:
                condA_ok = nums[0:i] == nums[i:2 * i]
            if condA_ok:
                count += (n - 1) - (2 * i) + 1

            suf = nums[i:]
            m = len(suf)
            z = [0] * m
            l, r = 0, 0
            for k in range(1, m):
                if k < r:
                    z[k] = min(r - k, z[k - l])
                while k + z[k] < m and suf[z[k]] == suf[k + z[k]]:
                    z[k] += 1
                if k + z[k] > r:
                    l, r = k, k + z[k]

            for j in range(i + 1, n):
                offset = j - i
                if offset >= m:
                    continue
                if 2 * j - i > n:
                    continue
                if condA_ok and j >= 2 * i:
                    continue
                length_needed = j - i
                if z[offset] >= length_needed:
                    count += 1
        return count

