var beautifulSplits = function(nums) {
    const n = nums.length;
    let count = 0;
    for (let i = 1; i < n - 1; i++) {
        let condAOk = false;
        if (2 * i <= n) {
            condAOk = true;
            for (let t = 0; t < i; t++) {
                if (nums[t] !== nums[i + t]) { condAOk = false; break; }
            }
        }
        if (condAOk) {
            count += (n - 1) - (2 * i) + 1;
        }

        const suf = nums.slice(i);
        const m = suf.length;
        const z = new Array(m).fill(0);
        let l = 0, r = 0;
        for (let k = 1; k < m; k++) {
            if (k < r) {
                z[k] = Math.min(r - k, z[k - l]);
            }
            while (k + z[k] < m && suf[z[k]] === suf[k + z[k]]) {
                z[k]++;
            }
            if (k + z[k] > r) {
                l = k; r = k + z[k];
            }
        }

        for (let j = i + 1; j < n; j++) {
            const offset = j - i;
            if (offset >= m) continue;
            if (2 * j - i > n) continue;
            if (condAOk && j >= 2 * i) continue;
            const lengthNeeded = j - i;
            if (z[offset] >= lengthNeeded) count++;
        }
    }
    return count;
};
